fn max(a: i64, b: i64) -> i64 = if a > b { a } else { b };

fn main() -> i64 = {
    let n: i64 = read_int();
    let W: i64 = read_int();

    let weights: i64 = vec_new();
    let values: i64 = vec_new();

    for i in 0..n {
        let w: i64 = read_int();
        let v: i64 = read_int();
        vec_push(weights, w);
        vec_push(values, v);
        ()
    };

    // dp[j] = max value achievable with capacity j
    let dp: i64 = vec_new();
    for j in 0..(W + 1) {
        vec_push(dp, 0);
        ()
    };

    // Process each item
    for i in 0..n {
        let wi: i64 = vec_get(weights, i);
        let vi: i64 = vec_get(values, i);

        // Go backwards to avoid using same item twice
        let j: i64 = W;
        while j >= wi {
            let without: i64 = vec_get(dp, j);
            let with: i64 = vec_get(dp, j - wi) + vi;
            vec_set(dp, j, max(without, with));
            j = j - 1;
            ()
        };
        ()
    };

    let result: i64 = vec_get(dp, W);
    println(result);

    vec_free(weights);
    vec_free(values);
    vec_free(dp);

    0
};
